// store.ts
import { atom } from 'jotai'
export const darkModeAtom = atom(false)

import { useAtom } from 'jotai'
import { darkModeAtom } from './store'

function Toggle() {
  const [dark, setDark] = useAtom(darkModeAtom)
  return <button onClick={() => setDark(v => !v)}>{dark ? '🌙' : '☀️'}</button>
}

function Page() {
  const dark = useAtomValue(darkModeAtom)  // read-only, no re-render on write
  return <div className={dark ? 'dark' : ''}><Toggle /></div>
}

